import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect, useCallback } from 'react';
import type { StartupListing } from './types';
import { Page } from './types';
import { generateStartupListings } from './services/geminiService';
import Header from './components/Header';
import Footer from './components/Footer';
import HomePage from './components/HomePage';
import ListingsPage from './components/ListingsPage';
import ListingDetail from './components/ListingDetail';
import ListStartupForm from './components/ListStartupForm';
import LoadingSpinner from './components/LoadingSpinner';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<Page>(Page.Home);
  const [listings, setListings] = useState<StartupListing[]>([]);
  const [selectedListing, setSelectedListing] = useState<StartupListing | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);

  const fetchListings = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    try {
      const generatedListings = await generateStartupListings(9);
      setListings(generatedListings);
    } catch (e) {
      console.error(e);
      setError('Failed to generate startup listings. Please check your API key and try again.');
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchListings();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleNavigate = (page: Page) => {
    setCurrentPage(page);
    setSelectedListing(null);
    window.scrollTo(0, 0);
  };

  const handleViewDetails = (listing: StartupListing) => {
    setSelectedListing(listing);
    setCurrentPage(Page.Details);
    window.scrollTo(0, 0);
  };

  const handleAddListing = (newListing: Omit<StartupListing, 'id'>) => {
    const listingWithId = { ...newListing, id: Date.now().toString() };
    setListings(prev => [listingWithId, ...prev]);
    handleNavigate(Page.Listings);
  };

  const renderContent = () => {
    if (isLoading) {
      return <LoadingSpinner />;
    }
    if (error) {
        return <div className="text-center py-20 text-red-400">{error}</div>;
    }

    switch (currentPage) {
      case Page.Home:
        return <HomePage onNavigate={handleNavigate} featuredListings={listings.slice(0, 3)} onViewDetails={handleViewDetails} />;
      case Page.Listings:
        return <ListingsPage listings={listings} onViewDetails={handleViewDetails} />;
      case Page.Details:
        return selectedListing ? <ListingDetail listing={selectedListing} onBack={() => handleNavigate(Page.Listings)} /> : <ListingsPage listings={listings} onViewDetails={handleViewDetails} />;
      case Page.ListStartup:
        return <ListStartupForm onAddListing={handleAddListing} />;
      default:
        return <HomePage onNavigate={handleNavigate} featuredListings={listings.slice(0, 3)} onViewDetails={handleViewDetails} />;
    }
  };

  return (
    <div className="min-h-screen flex flex-col font-sans">
      <Header onNavigate={handleNavigate} />
      <main className="flex-grow container mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {renderContent()}
      </main>
      <Footer />
    </div>
  );
};

export default App;

export interface StartupListing {
  id: string;
  name: string;
  tagline: string;
  description: string;
  problem: string;
  solution: string;
  techStack: string[];
  mrr: number;
  users: number;
  price: number;
  whatYouGet: string[];
}

export enum Page {
    Home = 'home',
    Listings = 'listings',
    Details = 'details',
    ListStartup = 'list-startup'
}

import { GoogleGenAI, Type } from "@google/genai";
import type { StartupListing } from '../types';

const API_KEY = process.env.API_KEY;

if (!API_KEY) {
  throw new Error("API_KEY environment variable not set");
}

const ai = new GoogleGenAI({ apiKey: API_KEY });

const responseSchema = {
    type: Type.ARRAY,
    items: {
      type: Type.OBJECT,
      properties: {
        name: { type: Type.STRING, description: "The name of the startup." },
        tagline: { type: Type.STRING, description: "A catchy one-liner for the startup." },
        description: { type: Type.STRING, description: "A detailed paragraph describing the startup." },
        problem: { type: Type.STRING, description: "The problem this startup solves." },
        solution: { type: Type.STRING, description: "How the startup solves the problem." },
        techStack: { type: Type.ARRAY, items: { type: Type.STRING }, description: "List of technologies used." },
        mrr: { type: Type.NUMBER, description: "Monthly Recurring Revenue in USD." },
        users: { type: Type.NUMBER, description: "Total number of users." },
        price: { type: Type.NUMBER, description: "The asking price in USD." },
        whatYouGet: { type: Type.ARRAY, items: { type: Type.STRING }, description: "List of assets included in the sale." },
      },
      required: ["name", "tagline", "description", "problem", "solution", "techStack", "mrr", "users", "price", "whatYouGet"],
    },
};


export const generateStartupListings = async (count: number): Promise<StartupListing[]> => {
  try {
    const prompt = `
      You are an expert startup analyst. Generate a list of ${count} realistic, fictional startup ideas that are for sale. 
      For each startup, provide all the required details. Make the financial numbers (MRR, Users, Price) plausible for each other and the idea.
      Ensure the output is a valid JSON array of objects.
    `;

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    const jsonText = response.text.trim();
    const listingsData: Omit<StartupListing, 'id'>[] = JSON.parse(jsonText);

    return listingsData.map((listing, index) => ({
      ...listing,
      id: `${Date.now()}-${index}`
    }));

  } catch (error) {
    console.error("Error generating startup listings with Gemini:", error);
    throw new Error("Failed to fetch data from Gemini API.");
  }
};

