import React, { useState, useEffect, useCallback } from 'react';
import type { StartupListing } from './types';
import { Page } from './types';
import { generateStartupListings } from './services/geminiService';
import Header from './components/Header';
import Footer from './components/Footer';
import HomePage from './components/HomePage';
import ListingsPage from './components/ListingsPage';
import ListingDetail from './components/ListingDetail';
import ListStartupForm from './components/ListStartupForm';
import LoadingSpinner from './components/LoadingSpinner';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<Page>(Page.Home);
  const [listings, setListings] = useState<StartupListing[]>([]);
  const [selectedListing, setSelectedListing] = useState<StartupListing | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);

  const fetchListings = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    try {
      const generatedListings = await generateStartupListings(9);
      setListings(generatedListings);
    } catch (e) {
      console.error(e);
      setError('Failed to generate startup listings. Please check your API key and try again.');
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchListings();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleNavigate = (page: Page) => {
    setCurrentPage(page);
    setSelectedListing(null);
    window.scrollTo(0, 0);
  };

  const handleViewDetails = (listing: StartupListing) => {
    setSelectedListing(listing);
    setCurrentPage(Page.Details);
    window.scrollTo(0, 0);
  };

  const handleAddListing = (newListing: Omit<StartupListing, 'id'>) => {
    const listingWithId = { ...newListing, id: Date.now().toString() };
    setListings(prev => [listingWithId, ...prev]);
    handleNavigate(Page.Listings);
  };

  const renderContent = () => {
    if (isLoading) {
      return <LoadingSpinner />;
    }
    if (error) {
        return <div className="text-center py-20 text-red-600 font-medium">{error}</div>;
    }

    switch (currentPage) {
      case Page.Home:
        return <HomePage onNavigate={handleNavigate} featuredListings={listings.slice(0, 3)} onViewDetails={handleViewDetails} />;
      case Page.Listings:
        return <ListingsPage listings={listings} onViewDetails={handleViewDetails} />;
      case Page.Details:
        return selectedListing ? <ListingDetail listing={selectedListing} onBack={() => handleNavigate(Page.Listings)} /> : <ListingsPage listings={listings} onViewDetails={handleViewDetails} />;
      case Page.ListStartup:
        return <ListStartupForm onAddListing={handleAddListing} />;
      default:
        return <HomePage onNavigate={handleNavigate} featuredListings={listings.slice(0, 3)} onViewDetails={handleViewDetails} />;
    }
  };

  return (
    <div className="min-h-screen flex flex-col font-sans">
      <Header onNavigate={handleNavigate} />
      <main className="flex-grow container mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {renderContent()}
      </main>
      <Footer />
    </div>
  );
};

export default App;

