const ListStartupForm: React.FC<ListStartupFormProps> = ({ onAddListing }) => {
  const [formData, setFormData] = useState({
    name: '',
    tagline: '',
    description: '',
    problem: '',
    solution: '',
    techStack: '',
    mrr: '',
    users: '',
    price: '',
    whatYouGet: ''
  });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const newListing = {
        name: formData.name,
        tagline: formData.tagline,
        description: formData.description,
        problem: formData.problem,
        solution: formData.solution,
        techStack: formData.techStack.split(',').map(s => s.trim()),
        mrr: parseInt(formData.mrr, 10) || 0,
        users: parseInt(formData.users, 10) || 0,
        price: parseInt(formData.price, 10) || 0,
        whatYouGet: formData.whatYouGet.split(',').map(s => s.trim()),
    };
    onAddListing(newListing);
  };

  return (
    <div className="max-w-2xl mx-auto bg-base-200 p-8 rounded-xl border border-gray-200">
      <h1 className="text-3xl font-bold text-content-100 mb-4 text-center">Sell Your Startup</h1>
      <p className="text-center text-content-200 mb-8">Fill out the details below to create your listing. Be as detailed as possible to attract the right buyers.</p>
      <form onSubmit={handleSubmit} className="space-y-6">
        <InputField label="Startup Name" name="name" value={formData.name} onChange={handleChange} placeholder="e.g., AI Meeting Scribe" />
        <InputField label="Tagline" name="tagline" value={formData.tagline} onChange={handleChange} placeholder="A short, catchy description" />
        <TextAreaField label="Full Description" name="description" value={formData.description} onChange={handleChange} placeholder="Describe what your startup does in detail." />
        <TextAreaField label="Problem" name="problem" value={formData.problem} onChange={handleChange} placeholder="What problem does your startup solve?" />
        <TextAreaField label="Solution" name="solution" value={formData.solution} onChange={handleChange} placeholder="How does your startup solve this problem?" />
        <InputField label="Tech Stack (comma-separated)" name="techStack" value={formData.techStack} onChange={handleChange} placeholder="React, Node.js, Python" />
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <InputField label="MRR ($)" name="mrr" value={formData.mrr} onChange={handleChange} type="number" placeholder="2500" />
            <InputField label="Users" name="users" value={formData.users} onChange={handleChange} type="number" placeholder="150" />
            <InputField label="Price ($)" name="price" value={formData.price} onChange={handleChange} type="number" placeholder="75000" />
        </div>
        <InputField label="What's Included (comma-separated)" name="whatYouGet" value={formData.whatYouGet} onChange={handleChange} placeholder="Domain, Source Code, Customer List" />

        <div className="pt-4">
             <button type="submit" className="w-full bg-brand-primary text-white font-bold py-3 px-4 rounded-lg hover:bg-opacity-90 transition-colors text-lg">
                Create Listing
            </button>
        </div>
      </form>
    </div>
  );
};

