import { GoogleGenAI, Type } from "@google/genai";
import type { StartupListing } from '../types';

const API_KEY = process.env.API_KEY;

if (!API_KEY) {
  throw new Error("API_KEY environment variable not set");
}

const ai = new GoogleGenAI({ apiKey: API_KEY });

const responseSchema = {
    type: Type.ARRAY,
    items: {
      type: Type.OBJECT,
      properties: {
        name: { type: Type.STRING, description: "The name of the startup." },
        tagline: { type: Type.STRING, description: "A catchy one-liner for the startup." },
        description: { type: Type.STRING, description: "A detailed paragraph describing the startup." },
        problem: { type: Type.STRING, description: "The problem this startup solves." },
        solution: { type: Type.STRING, description: "How the startup solves the problem." },
        techStack: { type: Type.ARRAY, items: { type: Type.STRING }, description: "List of technologies used." },
        mrr: { type: Type.NUMBER, description: "Monthly Recurring Revenue in USD." },
        mrrVerified: { type: Type.BOOLEAN, description: "Whether the MRR is verified (e.g., via Stripe Connect)." },
        users: { type: Type.NUMBER, description: "Total number of users." },
        usersVerified: { type: Type.BOOLEAN, description: "Whether the user count is verified (e.g., via Google Analytics)." },
        price: { type: Type.NUMBER, description: "The asking price in USD." },
        whatYouGet: { type: Type.ARRAY, items: { type: Type.STRING }, description: "List of assets included in the sale." },
        founder: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING, description: "The founder's name." },
            bio: { type: Type.STRING, description: "A short, professional bio for the founder." },
          },
          required: ["name", "bio"],
        },
        qna: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              question: { type: Type.STRING },
              answer: { type: Type.STRING },
            },
            required: ["question", "answer"],
          },
          description: "Answers to key questions a buyer would ask."
        },
      },
      required: ["name", "tagline", "description", "problem", "solution", "techStack", "mrr", "mrrVerified", "users", "usersVerified", "price", "whatYouGet", "founder", "qna"],
    },
};


export const generateStartupListings = async (count: number): Promise<StartupListing[]> => {
  try {
    const prompt = `
      You are an expert startup analyst creating listings for a marketplace. Generate a list of ${count} realistic, fictional startup ideas that are for sale.

      For each startup, you must provide all the required details according to the schema.

      Crucially, for the Q&A section, you MUST generate thoughtful answers for the following THREE questions:
      1. What is your unique competitive advantage?
      2. What is your primary customer acquisition strategy?
      3. Why are you selling this business?

      Make the financial numbers (MRR, Users, Price) plausible for each other and the idea. Randomly set the 'mrrVerified' and 'usersVerified' flags to true or false to simulate a real marketplace.
      Ensure the output is a valid JSON array of objects.
    `;

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    const jsonText = response.text.trim();
    const listingsData: Omit<StartupListing, 'id'>[] = JSON.parse(jsonText);

    return listingsData.map((listing, index) => ({
      ...listing,
      id: `${Date.now()}-${index}`
    }));

  } catch (error) {
    console.error("Error generating startup listings with Gemini:", error);
    throw new Error("Failed to fetch data from Gemini API.");
  }
};

