import React, { useState, useEffect, useCallback } from 'react';
import type { Note } from './types';
import { Page } from './types';
import { generateNotes } from './services/geminiService';
import ListingsPage from './components/ListingsPage';
import ListingDetail from './components/ListingDetail';
import ListStartupForm from './components/ListStartupForm';
import LoadingSpinner from './components/LoadingSpinner';
import { MicrophoneIcon } from './components/icons/CheckCircleIcon';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<Page>(Page.Home);
  const [notes, setNotes] = useState<Note[]>([]);
  const [selectedNote, setSelectedNote] = useState<Note | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);

  const fetchNotes = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    try {
      const generatedNotes = await generateNotes(9);
      setNotes(generatedNotes);
    } catch (e) {
      console.error(e);
      setError('Failed to generate ideas. Please check your API key and try again.');
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchNotes();
  }, [fetchNotes]);

  const handleNavigate = (page: Page) => {
    setCurrentPage(page);
    setSelectedNote(null);
    window.scrollTo(0, 0);
  };

  const handleViewDetails = (note: Note) => {
    setSelectedNote(note);
    setCurrentPage(Page.Details);
    window.scrollTo(0, 0);
  };

  const handleAddNote = (newNote: Omit<Note, 'id'>) => {
    const noteWithId = { 
      ...newNote, 
      id: Date.now().toString(),
      createdAt: new Intl.DateTimeFormat('en-US', { month: 'short', day: '2-digit', year: 'numeric' }).format(new Date())
    };
    setNotes(prev => [noteWithId, ...prev]);
    handleNavigate(Page.Home);
  };

  const renderContent = () => {
    if (isLoading) {
      return <LoadingSpinner />;
    }
    if (error) {
        return <div className="text-center py-20 text-red-600 font-medium">{error}</div>;
    }

    switch (currentPage) {
      case Page.Home:
      case Page.Listings:
        return <ListingsPage notes={notes} onViewDetails={handleViewDetails} />;
      case Page.Details:
        return selectedNote ? <ListingDetail note={selectedNote} onBack={() => handleNavigate(Page.Home)} /> : <ListingsPage notes={notes} onViewDetails={handleViewDetails} />;
      case Page.NewNote:
        return <ListStartupForm onAddNote={handleAddNote} />;
      default:
        return <ListingsPage notes={notes} onViewDetails={handleViewDetails} />;
    }
  };

  const isDetailsPage = currentPage === Page.Details;

  return (
    <div className={isDetailsPage ? 'bg-details-bg' : 'bg-base-100'}>
      <div className="relative min-h-screen">
        <main className="container mx-auto px-4 sm:px-6 lg:px-8 py-8">
          {renderContent()}
        </main>

        {!isDetailsPage && (
          <button 
            onClick={() => setCurrentPage(Page.NewNote)}
            className="fixed bottom-8 right-8 bg-brand-primary text-white h-16 w-16 rounded-full flex items-center justify-center shadow-lg hover:scale-110 transition-transform"
            aria-label="Create new note"
          >
            <MicrophoneIcon className="h-8 w-8" />
          </button>
        )}
      </div>
    </div>
  );
};

export default App;

