import { GoogleGenAI, Type } from "@google/genai";
import type { Note } from '../types';

const API_KEY = process.env.API_KEY;

if (!API_KEY) {
  throw new Error("API_KEY environment variable not set");
}

const ai = new GoogleGenAI({ apiKey: API_KEY });

const responseSchema = {
    type: Type.ARRAY,
    items: {
      type: Type.OBJECT,
      properties: {
        title: { type: Type.STRING, description: "A creative and engaging title for the note or idea." },
        content: { type: Type.STRING, description: "The main body of the note, two or three sentences long." },
        createdAt: { type: Type.STRING, description: "A realistic date for when the note was created, in 'Mon DD, YYYY' format (e.g., Jan 07, 2026)." },
      },
      required: ["title", "content", "createdAt"],
    },
};


export const generateNotes = async (count: number): Promise<Note[]> => {
  try {
    const prompt = `
      You are a creative assistant. Generate a list of ${count} fictional notes. Each note should have a title, a short content body, and a creation date.
      The topics can range from tech ideas, project updates, to philosophical musings.
      Ensure the output is a valid JSON array of objects.
    `;

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    const jsonText = response.text.trim();
    const notesData: Omit<Note, 'id'>[] = JSON.parse(jsonText);

    return notesData.map((note, index) => ({
      ...note,
      id: `${Date.now()}-${index}`
    }));

  } catch (error) {
    console.error("Error generating notes with Gemini:", error);
    throw new Error("Failed to fetch data from Gemini API.");
  }
};

