import React, { useState } from 'react';
import type { Note } from '../types';

interface NoteFormProps {
  onAddNote: (note: Omit<Note, 'id' | 'createdAt'>) => void;
}

const ListStartupForm: React.FC<NoteFormProps> = ({ onAddNote }) => {
  const [title, setTitle] = useState('');
  const [content, setContent] = useState('');

  const handleSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    if (!title.trim() || !content.trim()) return;
    onAddNote({ title, content });
  };

  return (
    <div className="max-w-3xl mx-auto py-12">
      <h1 className="font-serif text-5xl font-bold text-center text-content-100 mb-12">New Note</h1>
      <form onSubmit={handleSubmit} className="space-y-8">
        <div>
          <input
            type="text"
            placeholder="Title"
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            required
            className="w-full bg-transparent font-serif text-4xl text-content-100 placeholder-content-200/50 focus:outline-none border-b-2 border-base-300 focus:border-brand-primary transition-colors py-2"
          />
        </div>
        <div>
           <textarea
            placeholder="Start writing your idea..."
            value={content}
            onChange={(e) => setContent(e.target.value)}
            required
            rows={10}
            className="w-full bg-base-200/50 font-sans text-lg p-4 text-content-100 placeholder-content-200/70 rounded-lg focus:outline-none focus:ring-2 focus:ring-brand-primary transition-shadow"
          />
        </div>
        <div className="flex justify-end">
             <button type="submit" className="bg-brand-primary text-white font-bold py-3 px-8 rounded-full hover:opacity-90 transition-opacity text-lg">
                Save Note
            </button>
        </div>
      </form>
    </div>
  );
};

