);

const ListingDetail: React.FC<ListingDetailProps> = ({ listing, onBack }) => {
  const assetIcons: {[key: string]: React.ReactNode} = {
      'domain': <DomainIcon className="h-6 w-6" />,
      'code': <CodeIcon className="h-6 w-6" />,
      'customer': <UsersIcon className="h-6 w-6" />,
  }

  const getAssetIcon = (name: string) => {
      const lowerName = name.toLowerCase();
      if (lowerName.includes('domain')) return assetIcons['domain'];
      if (lowerName.includes('code') || lowerName.includes('repository')) return assetIcons['code'];
      if (lowerName.includes('customer') || lowerName.includes('user')) return assetIcons['customer'];
      return assetIcons['domain'];
  }

  return (
    <div className="fixed inset-0 z-50 bg-details-bg overflow-y-auto">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <button onClick={onBack} className="mb-8 text-details-content-200 hover:text-details-content-100 font-medium text-sm">&larr; Back to Marketplace</button>

        <div className="grid grid-cols-1 lg:grid-cols-3 lg:gap-16">
          {/* Left Sticky Column */}
          <div className="lg:col-span-1 lg:sticky top-8 self-start space-y-8">
              <div className="space-y-2">
                  <h1 className="text-5xl font-bold font-serif text-details-content-100 tracking-tighter">{listing.name}</h1>
                  <p className="text-lg text-details-content-200">{listing.tagline}</p>
              </div>

              <div className="bg-transparent border border-details-content-200/20 rounded-2xl p-6 space-y-6">
                   <Metric label="Asking Price" value={formatCurrency(listing.price)} verified={false} />
                   <Metric label="Monthly Recurring Revenue" value={formatCurrency(listing.mrr)} verified={listing.mrrVerified} />
                   <Metric label="Active Users" value={listing.users.toLocaleString()} verified={listing.usersVerified} />
              </div>

              <div className="bg-transparent border border-details-content-200/20 rounded-2xl p-6">
                  <h3 className="font-semibold text-details-content-100 mb-3">Founder</h3>
                  <p className="font-bold text-details-content-100">{listing.founder.name}</p>
                  <p className="text-sm text-details-content-200">{listing.founder.bio}</p>
              </div>

              <button className="w-full bg-brand-primary text-white font-bold py-4 px-6 rounded-full text-lg hover:opacity-90 transition-opacity">
                  Make an Offer
              </button>
          </div>

          {/* Right Scrolling Column */}
          <div className="lg:col-span-2 mt-12 lg:mt-0 divide-y divide-details-content-200/20">
              <DetailSection title="About the Business">
                  <p className="text-lg text-details-content-200">{listing.description}</p>
              </DetailSection>

              <DetailSection title="Growth Snapshot">
                  <div className="bg-transparent border border-details-content-200/20 rounded-2xl p-6 text-center">
                      <p className="font-semibold text-details-content-100">MRR Growth (Last 6 Months)</p>
                      <div className="h-48 flex items-center justify-center text-details-content-200">(Data visualization placeholder)</div>
                      <p className="text-xs text-details-content-200 mt-2">Connect your Stripe account to display a verified growth chart.</p>
                  </div>
              </DetailSection>

              <DetailSection title="Founder Q&A">
                  <div className="space-y-6">
                      {listing.qna.map((item, index) => (
                          <div key={index}>
                              <h4 className="font-semibold text-details-content-100">{item.question}</h4>
                              <p className="mt-1 text-details-content-200">{item.answer}</p>
                          </div>
                      ))}
                  </div>
              </DetailSection>

              <DetailSection title="Assets Included">
                  <div className="grid grid-cols-2 gap-4">
                      {listing.whatYouGet.map((item, index) => (
                          <Asset key={index} icon={getAssetIcon(item)} name={item} />
                      ))}
                  </div>
              </DetailSection>

              <DetailSection title="Tech Stack">
                  <div className="flex flex-wrap gap-3">
                      {listing.techStack.map((tech, index) => (
                          <span key={index} className="bg-details-content-200/10 text-details-content-100 px-4 py-1.5 rounded-full text-sm font-medium">{tech}</span>
                      ))}
                  </div>
              </DetailSection>

              <DetailSection title="Due Diligence Checklist">
                  <p className="text-details-content-200">Serious buyers will typically request the following for verification:</p>
                  <ul className="mt-4 space-y-2">
                      <DueDiligenceItem>Read-only access to analytics (Google Analytics, etc.)</DueDiligenceItem>
                      <DueDiligenceItem>Financial statements or screen-share of payment processor account</DueDiligenceItem>
                      <DueDiligenceItem>Review of the source code repository</DueDiligenceItem>
                  </ul>
              </DetailSection>
          </div>
        </div>
      </div>
    </div>
  );
};

