import React, { useState } from 'react';
import type { StartupListing } from '../types';

interface ListStartupFormProps {
  onAddListing: (listing: Omit<StartupListing, 'id'>) => void;
}

const FormSection: React.FC<{title: string, description: string, children: React.ReactNode}> = ({title, description, children}) => (
    <div className="grid grid-cols-1 md:grid-cols-3 gap-4 md:gap-8 py-8 border-b border-base-300">
        <div className="md:col-span-1">
            <h3 className="text-lg font-semibold text-content-100">{title}</h3>
            <p className="mt-1 text-sm text-content-200">{description}</p>
        </div>
        <div className="md:col-span-2 space-y-6">
            {children}
        </div>
    </div>
)

const InputField: React.FC<{ label: string; name: string; value: string | number; onChange: (e: React.ChangeEvent<HTMLInputElement>) => void; type?: string; placeholder?: string; required?: boolean }> = ({ label, name, value, onChange, type = "text", placeholder, required = true }) => (
    <div>
        <label htmlFor={name} className="block text-sm font-medium text-content-100 mb-1">{label}</label>
        <input
            type={type}
            id={name}
            name={name}
            value={value}
            onChange={onChange}
            placeholder={placeholder}
            required={required}
            className="block w-full bg-base-200 border-base-300 rounded-lg shadow-sm focus:ring-brand-primary focus:border-brand-primary sm:text-sm p-3"
        />
    </div>
);

const TextAreaField: React.FC<{ label: string; name: string; value: string; onChange: (e: React.ChangeEvent<HTMLTextAreaElement>) => void; placeholder?: string; required?: boolean }> = ({ label, name, value, onChange, placeholder, required = true }) => (
     <div>
        <label htmlFor={name} className="block text-sm font-medium text-content-100 mb-1">{label}</label>
        <textarea
            id={name}
            name={name}
            value={value}
            onChange={onChange}
            placeholder={placeholder}
            required={required}
            rows={5}
            className="block w-full bg-base-200 border-base-300 rounded-lg shadow-sm focus:ring-brand-primary focus:border-brand-primary sm:text-sm p-3"
        />
    </div>
);


const ListStartupForm: React.FC<ListStartupFormProps> = ({ onAddListing }) => {
  const [formData, setFormData] = useState({
    name: '',
    tagline: '',
    description: '',
    problem: '',
    solution: '',
    techStack: '',
    mrr: '',
    users: '',
    price: '',
    whatYouGet: ''
  });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const newListing: Omit<StartupListing, 'id' | 'founder' | 'qna' | 'mrrVerified' | 'usersVerified'> = {
        name: formData.name,
        tagline: formData.tagline,
        description: formData.description,
        problem: formData.problem,
        solution: formData.solution,
        techStack: formData.techStack.split(',').map(s => s.trim()),
        mrr: parseInt(formData.mrr, 10) || 0,
        users: parseInt(formData.users, 10) || 0,
        price: parseInt(formData.price, 10) || 0,
        whatYouGet: formData.whatYouGet.split(',').map(s => s.trim()),
    };
    // @ts-ignore
    onAddListing(newListing);
  };

  return (
    <div className="max-w-4xl mx-auto">
      <div className="text-center mb-12">
        <h1 className="text-5xl font-bold font-serif text-content-100 tracking-tight">List Your Startup</h1>
        <p className="mt-2 text-lg text-content-200">Share your story and financials to attract the perfect buyer.</p>
      </div>

      <form onSubmit={handleSubmit}>
        <FormSection title="Core Details" description="This is the first impression buyers will have. Make it count.">
            <InputField label="Startup Name" name="name" value={formData.name} onChange={handleChange} placeholder="e.g., AI Meeting Scribe" />
            <InputField label="Tagline" name="tagline" value={formData.tagline} onChange={handleChange} placeholder="A short, catchy one-liner." />
            <TextAreaField label="Full Description" name="description" value={formData.description} onChange={handleChange} placeholder="Describe what your startup does in detail." />
        </FormSection>

        <FormSection title="The Narrative" description="Help buyers understand the 'why' behind your business.">
            <TextAreaField label="Problem" name="problem" value={formData.problem} onChange={handleChange} placeholder="What specific problem does your startup solve?" />
            <TextAreaField label="Solution" name="solution" value={formData.solution} onChange={handleChange} placeholder="How does your startup solve this problem uniquely?" />
        </FormSection>

        <FormSection title="Financials & Metrics" description="Provide key metrics. Honesty and accuracy are crucial here.">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <InputField label="MRR ($)" name="mrr" value={formData.mrr} onChange={handleChange} type="number" placeholder="2500" />
                <InputField label="Users" name="users" value={formData.users} onChange={handleChange} type="number" placeholder="150" />
                <InputField label="Asking Price ($)" name="price" value={formData.price} onChange={handleChange} type="number" placeholder="75000" />
            </div>
        </FormSection>

        <FormSection title="Assets & Technology" description="List what the buyer will receive and the technology that powers your startup.">
            <InputField label="What's Included (comma-separated)" name="whatYouGet" value={formData.whatYouGet} onChange={handleChange} placeholder="Domain, Source Code, Customer List" />
            <InputField label="Tech Stack (comma-separated)" name="techStack" value={formData.techStack} onChange={handleChange} placeholder="React, Node.js, Python" />
        </FormSection>

        <div className="pt-8 flex justify-end">
             <button type="submit" className="bg-brand-primary text-white font-bold py-3 px-8 rounded-full hover:opacity-90 transition-colors text-lg">
                Submit Listing
            </button>
        </div>
      </form>
    </div>
  );
};

export default ListStartupForm;

