const ListStartupForm: React.FC<ListStartupFormProps> = ({ onAddListing }) => {
  const [formData, setFormData] = useState({
    name: '',
    tagline: '',
    description: '',
    problem: '',
    solution: '',
    techStack: '',
    mrr: '',
    users: '',
    price: '',
    whatYouGet: ''
  });

  const [errors, setErrors] = useState({
      mrr: '',
      users: '',
      price: ''
  });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));

    if (name === 'mrr' || name === 'users' || name === 'price') {
        const numValue = Number(value);
        if (value && (isNaN(numValue) || numValue < 0)) {
            setErrors(prev => ({...prev, [name]: 'Value must be a positive number.'}));
        } else {
            setErrors(prev => ({...prev, [name]: ''}));
        }
    }
  };

  const handleSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    if (Object.values(errors).some(error => error)) {
        return;
    }
    const newListing: Omit<StartupListing, 'id' | 'founder' | 'qna' | 'mrrVerified' | 'usersVerified'> = {
        name: formData.name,
        tagline: formData.tagline,
        description: formData.description,
        problem: formData.problem,
        solution: formData.solution,
        techStack: formData.techStack.split(',').map(s => s.trim()),
        mrr: parseInt(formData.mrr, 10) || 0,
        users: parseInt(formData.users, 10) || 0,
        price: parseInt(formData.price, 10) || 0,
        whatYouGet: formData.whatYouGet.split(',').map(s => s.trim()),
    };
    // @ts-ignore
    onAddListing(newListing);
  };

  const isFormValid = Object.values(formData).every(value => value.trim() !== '') && Object.values(errors).every(error => error === '');

  return (
