const ListStartupForm: React.FC<ListStartupFormProps> = ({ onAddListing }) => {
  const [formData, setFormData] = useState({
    name: '',
    tagline: '',
    category: '',
    description: '',
    problem: '',
    solution: '',
    techStack: '',
    mrr: '',
    users: '',
    price: '',
    whatYouGet: ''
  });

  const categories = ['SaaS', 'AI', 'E-commerce', 'Mobile', 'Web App', 'Fintech', 'Other'];

  const [errors, setErrors] = useState({
      mrr: '',
      users: '',
      price: ''
  });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));

    if (name === 'mrr' || name === 'users' || name === 'price') {
        const numValue = Number(value);
        if (value && (isNaN(numValue) || numValue < 0)) {
            setErrors(prev => ({...prev, [name]: 'Value must be a positive number.'}));
        } else {
            setErrors(prev => ({...prev, [name]: ''}));
        }
    }
  };

  const handleSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    if (Object.values(errors).some(error => error)) {
        return;
    }
    const newListing: Omit<StartupListing, 'id'> = {
        name: formData.name,
        tagline: formData.tagline,
        category: formData.category,
        description: formData.description,
        problem: formData.problem,
        solution: formData.solution,
        techStack: formData.techStack.split(',').map(s => s.trim()),
        mrr: parseInt(formData.mrr, 10) || 0,
        users: parseInt(formData.users, 10) || 0,
        price: parseInt(formData.price, 10) || 0,
        whatYouGet: formData.whatYouGet.split(',').map(s => s.trim()),
        founder: { name: 'Awaiting Founder Info', bio: 'The founder has not yet provided their bio.' },
        qna: [],
        mrrVerified: false,
        usersVerified: false,
    };
    onAddListing(newListing);
  };

  const isFormValid = Object.values(formData).every(value => value.trim() !== '') && Object.values(errors).every(error => error === '');

  return (
    <div className="max-w-4xl mx-auto">
      <div className="text-center mb-12">
        <h1 className="text-5xl font-bold font-serif text-content-100 tracking-tight">List Your Startup</h1>
        <p className="mt-2 text-lg text-content-200">Share your story and financials to attract the perfect buyer.</p>
      </div>

      <form onSubmit={handleSubmit}>
        <FormSection title="Core Details" description="This is the first impression buyers will have. Make it count.">
            <InputField label="Startup Name" name="name" value={formData.name} onChange={handleChange} placeholder="e.g., AI Meeting Scribe" />
            <InputField label="Tagline" name="tagline" value={formData.tagline} onChange={handleChange} placeholder="A short, catchy one-liner." />
            <SelectField label="Category" name="category" value={formData.category} onChange={handleChange}>
                <option value="" disabled>Select a category</option>
                {categories.map(cat => <option key={cat} value={cat}>{cat}</option>)}
            </SelectField>
            <TextAreaField label="Full Description" name="description" value={formData.description} onChange={handleChange} placeholder="Describe what your startup does in detail." />
        </FormSection>

        <FormSection title="The Narrative" description="Help buyers understand the 'why' behind your business.">
            <TextAreaField label="Problem" name="problem" value={formData.problem} onChange={handleChange} placeholder="What specific problem does your startup solve?" />
            <TextAreaField label="Solution" name="solution" value={formData.solution} onChange={handleChange} placeholder="How does your startup solve this problem uniquely?" />
        </FormSection>

        <FormSection title="Financials & Metrics" description="Provide key metrics. Honesty and accuracy are crucial here.">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <InputField label="MRR ($)" name="mrr" value={formData.mrr} onChange={handleChange} type="number" placeholder="2500" error={errors.mrr} />
                <InputField label="Users" name="users" value={formData.users} onChange={handleChange} type="number" placeholder="150" error={errors.users} />
                <InputField label="Asking Price ($)" name="price" value={formData.price} onChange={handleChange} type="number" placeholder="75000" error={errors.price} />
            </div>
        </FormSection>

        <FormSection title="Assets & Technology" description="List what the buyer will receive and the technology that powers your startup.">
            <InputField label="What's Included (comma-separated)" name="whatYouGet" value={formData.whatYouGet} onChange={handleChange} placeholder="Domain, Source Code, Customer List" />
            <InputField label="Tech Stack (comma-separated)" name="techStack" value={formData.techStack} onChange={handleChange} placeholder="React, Node.js, Python" />
        </FormSection>

        <div className="pt-8 flex justify-end">
             <button 
                type="submit" 
                disabled={!isFormValid}
                className="bg-brand-primary text-white font-bold py-3 px-8 rounded-full hover:opacity-90 transition-opacity text-lg disabled:opacity-50 disabled:cursor-not-allowed"
             >
                Submit Listing
            </button>
        </div>
      </form>
    </div>
  );
};

export default ListStartupForm;

payload.text:
**Initiating the Offer Feature**

I'm currently focused on implementing the "Make an Offer" functionality. My initial step is to build a dedicated modal. This modal will be triggered by a button click on the `ListingDetail` page, ensuring a user-friendly and clear interface for the offer process. It's the core of the new feature.


**Defining the Modal Structure**

I've moved on to solidify the 'Make an Offer' modal's structure. It's designed to be intuitive, starting with a clear startup name header. The form will feature pre-filled, editable price input, alongside name, email (with validation), and an optional message area. A concise disclaimer about the offer's non-binding nature will be included, with a disabled "Send Offer" button until all required fields are validated. I'll handle the modal's visibility with `isOfferModalOpen` and target the specific listing in `offeringForListing`.


**Outlining the Implementation**

I'm now outlining the steps to bring the "Make an Offer" feature to life. First, I'll build the dedicated modal, triggered by a button click on the `ListingDetail` page, which provides a clean user interface. The modal will have form fields including an offer amount, name, email with validation, and an optional message. It will also have a non-binding disclaimer. The "Send Offer" button stays disabled until validation passes. I'll utilize `isOfferModalOpen` and `offeringForListing` for state management.


**Defining the Detailed Steps**

