  const [listings, setListings] = useState<StartupListing[]>([]);
  const [sponsoredListings, setSponsoredListings] = useState<StartupListing[]>([]);
  const [selectedListing, setSelectedListing] = useState<StartupListing | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);

  // State for the offer modal
  const [isOfferModalOpen, setIsOfferModalOpen] = useState(false);
  const [offeringForListing, setOfferingForListing] = useState<StartupListing | null>(null);


  const fetchListings = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    try {
      const [generatedListings, generatedSponsored] = await Promise.all([
        generateStartupListings(9),
        generateSponsoredListings(6)
      ]);
      setListings(generatedListings);
      setSponsoredListings(generatedSponsored);
    } catch (e) {
      console.error(e);
      setError('Failed to generate startup listings. Please check your API key and try again.');
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchListings();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleNavigate = (page: Page) => {
    setCurrentPage(page);
    setSelectedListing(null);
    window.scrollTo(0, 0);
  };

  const handleViewDetails = (listing: StartupListing) => {
    setSelectedListing(listing);
    setCurrentPage(Page.Details);
    window.scrollTo(0, 0);
  };

  const handleAddListing = (newListing: Omit<StartupListing, 'id'>) => {
    const listingWithId = { ...newListing, id: Date.now().toString() };
    setListings(prev => [listingWithId, ...prev]);
    handleNavigate(Page.Listings);
  };

  // Handlers for the offer modal
  const handleOpenOfferModal = (listing: StartupListing) => {
    setOfferingForListing(listing);
    setIsOfferModalOpen(true);
  };

  const handleCloseOfferModal = () => {
    setIsOfferModalOpen(false);
    setOfferingForListing(null);
  };

  const handleSendOffer = (offerData: { amount: number; name: string; email: string; message: string }) => {
    console.log('Offer Sent:', {
      listingId: offeringForListing?.id,
      listingName: offeringForListing?.name,
      ...offerData,
    });
    // In a real app, this would send data to a backend.
    // The modal will show a success message after this function is called.
  };


  const renderContent = () => {
    if (isLoading) {
      return <LoadingSpinner />;
    }
    if (error) {
        return <div className="text-center py-20 text-red-600 font-medium">{error}</div>;
    }

    switch (currentPage) {
      case Page.Home:
        return <HomePage onNavigate={handleNavigate} featuredListings={listings.slice(0, 3)} onViewDetails={handleViewDetails} />;
      case Page.Listings:
        return <ListingsPage listings={listings} sponsoredListings={sponsoredListings} onViewDetails={handleViewDetails} />;
      case Page.Details:
        return selectedListing ? <ListingDetail listing={selectedListing} onBack={() => handleNavigate(Page.Listings)} onMakeOffer={handleOpenOfferModal} /> : <ListingsPage listings={listings} sponsoredListings={sponsoredListings} onViewDetails={handleViewDetails} />;
      case Page.ListStartup:
        return <ListStartupForm onAddListing={handleAddListing} />;
      default:
        return <HomePage onNavigate={handleNavigate} featuredListings={listings.slice(0, 3)} onViewDetails={handleViewDetails} />;
    }
  };

  return (
    <div className="min-h-screen flex flex-col font-sans">
      <Header onNavigate={handleNavigate} />
      <main className="flex-grow container mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {renderContent()}
      </main>
      <Footer />
      {isOfferModalOpen && (
        <OfferModal 
            listing={offeringForListing}
            onClose={handleCloseOfferModal}
            onSubmit={handleSendOffer}
        />
      )}
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import type { StartupListing } from '../types';

const API_KEY = process.env.API_KEY;

if (!API_KEY) {
  throw new Error("API_KEY environment variable not set");
}

const ai = new GoogleGenAI({ apiKey: API_KEY });

const responseSchema = {
    type: Type.ARRAY,
    items: {
      type: Type.OBJECT,
      properties: {
        name: { type: Type.STRING, description: "The name of the startup." },
        tagline: { type: Type.STRING, description: "A catchy one-liner for the startup." },
        category: { type: Type.STRING, description: "The category of the startup from the list: SaaS, AI, E-commerce, Mobile, Web App, Fintech." },
        description: { type: Type.STRING, description: "A detailed paragraph describing the startup." },
        problem: { type: Type.STRING, description: "The problem this startup solves." },
        solution: { type: Type.STRING, description: "How the startup solves the problem." },
        techStack: { type: Type.ARRAY, items: { type: Type.STRING }, description: "List of technologies used." },
        mrr: { type: Type.NUMBER, description: "Monthly Recurring Revenue in USD." },
        mrrVerified: { type: Type.BOOLEAN, description: "Whether the MRR is verified (e.g., via Stripe Connect)." },
        users: { type: Type.NUMBER, description: "Total number of users." },
        usersVerified: { type: Type.BOOLEAN, description: "Whether the user count is verified (e.g., via Google Analytics)." },
        price: { type: Type.NUMBER, description: "The asking price in USD." },
        whatYouGet: { type: Type.ARRAY, items: { type: Type.STRING }, description: "List of assets included in the sale." },
        founder: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING, description: "The founder's name." },
            bio: { type: Type.STRING, description: "A short, professional bio for the founder." },
          },
          required: ["name", "bio"],
        },
        qna: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              question: { type: Type.STRING },
              answer: { type: Type.STRING },
            },
            required: ["question", "answer"],
          },
          description: "Answers to key questions a buyer would ask."
        },
      },
      required: ["name", "tagline", "category", "description", "problem", "solution", "techStack", "mrr", "mrrVerified", "users", "usersVerified", "price", "whatYouGet", "founder", "qna"],
    },
};


export const generateStartupListings = async (count: number): Promise<StartupListing[]> => {
  try {
    const prompt = `
      You are an expert startup analyst creating listings for a marketplace. Generate a list of ${count} realistic, fictional startup ideas that are for sale.

      For each startup, you must provide all the required details according to the schema.

      Assign a relevant category for each startup from this specific list: ['SaaS', 'AI', 'E-commerce', 'Mobile', 'Web App', 'Fintech'].

      Crucially, for the Q&A section, you MUST generate thoughtful answers for the following THREE questions:
      1. What is your unique competitive advantage?
      2. What is your primary customer acquisition strategy?
      3. Why are you selling this business?

      Make the financial numbers (MRR, Users, Price) plausible for each other and the idea. Randomly set the 'mrrVerified' and 'usersVerified' flags to true or false to simulate a real marketplace.
      Ensure the output is a valid JSON array of objects.
    `;

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    const jsonText = response.text.trim();
    const listingsData: Omit<StartupListing, 'id'>[] = JSON.parse(jsonText);

    return listingsData.map((listing, index) => ({
      ...listing,
      id: `${Date.now()}-${index}`
    }));

  } catch (error) {
    console.error("Error generating startup listings with Gemini:", error);
    throw new Error("Failed to fetch data from Gemini API.");
  }
};

export const generateSponsoredListings = async (count: number): Promise<StartupListing[]> => {
  try {
    const prompt = `
      You are an advertising expert creating a list of sponsored startups for a marketplace banner. Generate a list of ${count} compelling, fictional startups.
      These will be used for ads, so make their names and taglines extra catchy.
      For each startup, provide all the required details according to the schema.
      Assign a relevant category for each startup from this specific list: ['SaaS', 'AI', 'E-commerce', 'Mobile', 'Web App', 'Fintech'].
      Keep descriptions concise but powerful. Q&A can be more brief and punchy.
      Ensure the output is a valid JSON array of objects.
    `;

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    const jsonText = response.text.trim();
    const listingsData: Omit<StartupListing, 'id'>[] = JSON.parse(jsonText);

    return listingsData.map((listing, index) => ({
      ...listing,
      id: `sponsored-${Date.now()}-${index}`
    }));

  } catch (error) {
    console.error("Error generating sponsored listings with Gemini:", error);
    // Return empty array on error to not break the page
    return [];
  }
};

import React, { useState, useMemo } from 'react';
import type { StartupListing } from '../types';
import StartupCard from './StartupCard';
import Filters from './Filters';
import SponsoredBanner from './SponsoredBanner';

interface ListingsPageProps {
  listings: StartupListing[];
  sponsoredListings: StartupListing[];
  onViewDetails: (listing: StartupListing) => void;
}

const ListingsPage: React.FC<ListingsPageProps> = ({ listings, sponsoredListings, onViewDetails }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [activeCategory, setActiveCategory] = useState('All');
  const [sortOption, setSortOption] = useState('default');

  const categories = ['All', 'SaaS', 'AI', 'E-commerce', 'Mobile', 'Web App', 'Fintech'];

  const filteredAndSortedListings = useMemo(() => {
    let result = listings;

    // Category filter
    if (activeCategory !== 'All') {
      result = result.filter(listing => listing.category === activeCategory);
    }

    // Search filter
    if (searchTerm.trim() !== '') {
      const lowercasedSearchTerm = searchTerm.toLowerCase();
      result = result.filter(listing =>
        listing.name.toLowerCase().includes(lowercasedSearchTerm) ||
        listing.tagline.toLowerCase().includes(lowercasedSearchTerm)
      );
    }

    // Sorting
    const sortedResult = [...result]; // Create a copy to avoid mutating the original array
    switch (sortOption) {
      case 'price-desc':
        sortedResult.sort((a, b) => b.price - a.price);
        break;
      case 'price-asc':
        sortedResult.sort((a, b) => a.price - b.price);
        break;
      case 'mrr-desc':
        sortedResult.sort((a, b) => b.mrr - a.mrr);
        break;
      case 'users-desc':
        sortedResult.sort((a, b) => b.users - a.users);
        break;
      default:
        break;
    }

    return sortedResult;
  }, [listings, searchTerm, activeCategory, sortOption]);

  return (
    <div className="space-y-12 pb-28">
      <div className="text-center">
        <h1 className="text-5xl font-bold font-serif text-content-100 tracking-tight">Marketplace</h1>
        <p className="mt-2 text-lg text-content-200">Discover your next profitable venture.</p>
      </div>

      <Filters 
        searchTerm={searchTerm}
        onSearchChange={setSearchTerm}
        activeCategory={activeCategory}
        onCategoryChange={setActiveCategory}
        sortOption={sortOption}
        onSortChange={setSortOption}
        categories={categories}
      />

      {filteredAndSortedListings.length > 0 ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {filteredAndSortedListings.map(listing => (
            <StartupCard key={listing.id} listing={listing} onViewDetails={onViewDetails} />
          ))}
        </div>
      ) : (
        <p className="text-center text-content-200 py-16">No listings match your criteria.</p>
      )}

      {sponsoredListings.length > 0 && (
        <SponsoredBanner listings={sponsoredListings} onViewDetails={onViewDetails} />
      )}
    </div>
  );
};

export default ListingsPage;

import React from 'react';
import type { StartupListing } from '../types';
import SponsoredCard from './SponsoredCard';
import { MegaphoneIcon } from './icons/MegaphoneIcon';

interface SponsoredBannerProps {
  listings: StartupListing[];
  onViewDetails: (listing: StartupListing) => void;
}

const SponsoredBanner: React.FC<SponsoredBannerProps> = ({ listings, onViewDetails }) => {
  // Duplicate the listings to create a seamless loop
  const extendedListings = [...listings, ...listings];

  return (
