const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', minimumFractionDigits: 0 }).format(amount);
}

const DetailSection: React.FC<{ title: string; children: React.ReactNode }> = ({ title, children }) => (
    <div className="py-8">
        <h3 className="text-xl font-bold font-serif text-content-100 mb-4 tracking-tight">{title}</h3>
        <div className="space-y-4 text-content-200 leading-relaxed">{children}</div>
    </div>
);

const Metric: React.FC<{ label: string, value: string | number, verified: boolean }> = ({label, value, verified}) => (
    <div>
        <div className="flex items-center space-x-2">
            <p className="text-sm text-content-200">{label}</p>
            {verified && (
                <div className="flex items-center text-xs text-green-600 bg-green-100 px-2 py-0.5 rounded-full">
