const ListingDetail: React.FC<ListingDetailProps> = ({ listing, listings, onBack, onMakeOffer, onViewDetails }) => {
  const assetIcons: {[key: string]: React.ReactNode} = {
      'domain': <DomainIcon className="h-6 w-6" />,
      'code': <CodeIcon className="h-6 w-6" />,
      'customer': <UsersIcon className="h-6 w-6" />,
  }

  const getAssetIcon = (name: string) => {
      const lowerName = name.toLowerCase();
      if (lowerName.includes('domain')) return assetIcons['domain'];
      if (lowerName.includes('code') || lowerName.includes('repository')) return assetIcons['code'];
      if (lowerName.includes('customer') || lowerName.includes('user')) return assetIcons['customer'];
      return assetIcons['domain'];
  }

  const relatedListings = listings
    .filter(l => l.id !== listing.id && l.category === listing.category)
    .slice(0, 6);

  return (
    <div>
      <div className="max-w-7xl mx-auto">
        <button onClick={onBack} className="mb-8 text-content-200 hover:text-content-100 font-medium text-sm">&larr; Back to Marketplace</button>

        <div className="grid grid-cols-1 lg:grid-cols-3 lg:gap-16">
          {/* Left Sticky Column */}
          <div className="lg:col-span-1 lg:sticky top-28 self-start space-y-8">
              <div className="space-y-2">
                  <div className="flex items-center flex-wrap gap-2">
                    <span className="text-sm font-semibold bg-brand-primary/10 text-brand-primary px-3 py-1 rounded-full">{listing.category}</span>
                    <span className="text-sm font-semibold bg-blue-100 text-blue-800 px-3 py-1 rounded-full">{listing.businessType}</span>
                  </div>
                  <h1 className="text-5xl font-bold font-serif text-content-100 tracking-tighter pt-2">{listing.name}</h1>
                  <p className="text-lg text-content-200">{listing.tagline}</p>
              </div>

              <div className="bg-base-200 border border-base-300 rounded-2xl p-6 space-y-6">
                   <Metric label="Asking Price" value={formatCurrency(listing.price)} verified={false} />
                   <Metric label="Monthly Recurring Revenue" value={formatCurrency(listing.mrr)} verified={listing.mrrVerified} />
                   <Metric label="Active Users" value={listing.users.toLocaleString()} verified={listing.usersVerified} />
              </div>

              <div className="bg-base-200 border border-base-300 rounded-2xl p-6">
                  <h3 className="font-semibold text-content-100 mb-3">Founder</h3>
                  <p className="font-bold text-content-100">{listing.founder.name}</p>
                  <p className="text-sm text-content-200">{listing.founder.bio}</p>
              </div>

              <div className="space-y-4">
                {listing.projectUrl && (
                  <a
                    href={listing.projectUrl}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="w-full block text-center border-2 border-brand-primary text-brand-primary font-bold py-3.5 px-6 rounded-full text-lg hover:bg-brand-primary/10 transition-colors"
                  >
                    View Startup
                  </a>
                )}
                <button 
                  onClick={() => onMakeOffer(listing)}
                  className="w-full bg-brand-primary text-white font-bold py-4 px-6 rounded-full text-lg hover:opacity-90 transition-opacity"
                >
                    Make an Offer
                </button>
              </div>
          </div>

          {/* Right Scrolling Column */}
          <div className="lg:col-span-2 mt-12 lg:mt-0 divide-y divide-base-300">
              <DetailSection title="The Opportunity">
                  <div className="space-y-6">
                      <div>
                          <h4 className="font-bold text-content-100">The Problem</h4>
                          <p className="mt-1 text-content-200 leading-relaxed">{listing.problem}</p>
                      </div>
                      <div>
                          <h4 className="font-bold text-content-100">The Solution</h4>
                          <p className="mt-1 text-content-200 leading-relaxed">{listing.solution}</p>
                      </div>
                      <div>
                          <h4 className="font-bold text-content-100">Target Audience</h4>
                          <p className="mt-1 text-content-200 leading-relaxed">{listing.targetAudience}</p>
                      </div>
                      <div>
                          <h4 className="font-bold text-content-100">Business Summary</h4>
                          <p className="mt-1 text-content-200 leading-relaxed">{listing.description}</p>
                      </div>
                  </div>
              </DetailSection>

              <DetailSection title="Growth Snapshot">
                  <div className="bg-base-200 border border-base-300 rounded-2xl p-6 text-center">
                      <p className="font-semibold text-content-100">MRR Growth (Last 6 Months)</p>
                      <div className="h-48 flex items-center justify-center text-content-200">(Data visualization placeholder)</div>
                      <p className="text-xs text-content-200 mt-2">Connect your Stripe account to display a verified growth chart.</p>
                  </div>
              </DetailSection>

              <DetailSection title="Founder Q&A">
                  <div className="space-y-6">
                      {listing.qna.map((item, index) => (
                          <div key={index}>
                              <h4 className="font-semibold text-content-100">{item.question}</h4>
                              <p className="mt-1 text-content-200">{item.answer}</p>
                          </div>
                      ))}
