const ListStartupForm: React.FC<ListStartupFormProps> = ({ onAddListing }) => {
  const [formData, setFormData] = useState({
    name: '',
    tagline: '',
    projectUrl: '',
    category: '',
    description: '',
    problem: '',
    solution: '',
    targetAudience: '',
    businessType: '',
    techStack: '',
    mrr: '',
    users: '',
    price: '',
    whatYouGet: ''
  });

  const categories = ['SaaS', 'AI', 'E-commerce', 'Mobile', 'Web App', 'Fintech', 'HealthTech', 'EdTech', 'Creator Economy', 'Developer Tools', 'Gaming', 'GreenTech', 'Other'];

  const [errors, setErrors] = useState({
      mrr: '',
      users: '',
      price: ''
  });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));

    if (name === 'mrr' || name === 'users' || name === 'price') {
        const numValue = Number(value);
        if (value && (isNaN(numValue) || numValue < 0)) {
            setErrors(prev => ({...prev, [name]: 'Value must be a positive number.'}));
        } else {
            setErrors(prev => ({...prev, [name]: ''}));
        }
    }
  };

  const handleSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    if (Object.values(errors).some(error => error)) {
        return;
    }
    const newListing: Omit<StartupListing, 'id'> = {
        name: formData.name,
        tagline: formData.tagline,
        projectUrl: formData.projectUrl,
        category: formData.category,
        description: formData.description,
        problem: formData.problem,
        solution: formData.solution,
        targetAudience: formData.targetAudience,
        businessType: formData.businessType as 'B2B' | 'B2C',
        techStack: formData.techStack.split(',').map(s => s.trim()),
        mrr: parseInt(formData.mrr, 10) || 0,
        users: parseInt(formData.users, 10) || 0,
        price: parseInt(formData.price, 10) || 0,
        whatYouGet: formData.whatYouGet.split(',').map(s => s.trim()),
        founder: { name: 'Awaiting Founder Info', bio: 'The founder has not yet provided their bio.' },
        qna: [],
        mrrVerified: false,
        usersVerified: false,
    };
    onAddListing(newListing);
  };

  // Fix: Check if the value is a string before calling trim() to satisfy TypeScript's type checker.
  const isFormValid = Object.values(formData).every(value => typeof value === 'string' && value.trim() !== '') && Object.values(errors).every(error => error === '');

  return (
    <div className="max-w-4xl mx-auto">
      <div className="text-center mb-12">
        <h1 className="text-5xl font-bold font-serif text-content-100 tracking-tight">List Your Startup</h1>
        <p className="mt-2 text-lg text-content-200">Share your story and financials to attract the perfect buyer.</p>
      </div>

      <form onSubmit={handleSubmit}>
        <FormSection title="Core Details" description="This is the first impression buyers will have. Make it count.">
            <InputField label="Startup Name" name="name" value={formData.name} onChange={handleChange} placeholder="e.g., AI Meeting Scribe" />
            <InputField label="Tagline" name="tagline" value={formData.tagline} onChange={handleChange} placeholder="A short, catchy one-liner." />
