                  <div className="flex flex-wrap gap-3">
                      {listing.techStack.map((tech, index) => (
                          <span key={index} className="bg-base-300/50 border border-base-300 text-content-100 px-4 py-1.5 rounded-full text-sm font-medium">{tech}</span>
                      ))}
                  </div>
              </DetailSection>

              <DetailSection title="Due Diligence Checklist">
                  <p className="text-content-200">Serious buyers will typically request the following for verification:</p>
                  <ul className="mt-4 space-y-2">
                      <DueDiligenceItem>Read-only access to analytics (Google Analytics, etc.)</DueDiligenceItem>
                      <DueDiligenceItem>Financial statements or screen-share of payment processor account</DueDiligenceItem>
                      <DueDiligenceItem>Review of the source code repository</DueDiligenceItem>
                  </ul>
              </DetailSection>

              {relatedListings.length > 0 && (
                <DetailSection title="Similar Ventures">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
